return $input.all().flatMap(item => {
  const teamId = item.json.parameters?.team;
  const positionMap = {
    "Attacker":   "Forward",
    "Midfielder": "Midfielder",
    "Defender":   "Defender",
    "Goalkeeper": "Goalkeeper"
  };
  return (item.json.response || []).flatMap(entry =>
    (entry.players || []).map(p => ({
      json: {
        id: p.id,
        sport: "Football",
        teamId: Number(teamId),
        firstName: p.name?.split(' ')[0] ?? '',
        lastName: p.name?.split(' ').slice(1).join(' ') ?? '',
        position: positionMap[p.position] ?? "Midfielder",
        jerseyNumber: p.number !== undefined && p.number !== null ? p.number : null,
        imageUrl: p.photo && p.photo !== '' ? p.photo : null,
        hidden: false
      }
    }))
  );
});

const teamIds = new Set();

// Wir gehen durch das Array von n8n (meistens ein Item, das "items" enthält)
$input.all().forEach(item => {
  const matches = item.json.items || [];

  matches.forEach(m => {
    if (m.teamHomeId) teamIds.add(m.teamHomeId);
    if (m.teamAwayId) teamIds.add(m.teamAwayId);
  });
});

// Umwandlung in eine Liste für die API-Sports Squad Abfrage
return Array.from(teamIds).map(id => ({
  json: {
    teamId: id
  }
}));

